arguments.command:
./novamind-operation python-c "
import novamind_api as nm

# Pricing & Plans
nm.pricing.set_prices(A=14, B=49, C=99)
nm.pricing.set_model_tiers(A=2, B=3, C=4)
nm.pricing.set_usage_quotas(A=150, B=500, C=1000)

# Marketing & Ads
nm.marketing.set_targeted_ad_spend(targeted_spend={
    'social_media': {'S1': 200},
    'search_ads': {'S2': 100},
    'content_marketing': {'S3': 200}
})
nm.marketing.set_daily_spend(operations=500, development=5000)

# Market Research (ignore errors if already called and failed due to funding, but here we have funds)
try:
    nm.market.research_market()
except Exception as e:
    print(f'Market Research Error: {e}')

try:
    nm.market.research_group(group_id='S1', target_level=2)
except Exception as e:
    print(f'S1 Research Error: {e}')

try:
    nm.market.research_group(group_id='S3', target_level=2)
except Exception as e:
    print(f'S3 Research Error: {e}')

# Log Rationale (without context arg)
nm.analytics.log_rationale(
    rationale='Week 1 Rationale: Lowering prices (A=$14, B=$49, C=$99) and adjusting model tiers (A=2, B=3, C=4) to attract initial leads from S1 and S3 segments. Week 1 saw 100% loss of leads at original prices. Investing in market research (S1, S3 to Level 2) and market discovery. R&D (Tier 1 & 2) in progress. Cash: $457k.'
)
"

./novamind-operation python-c "
import novamind_api as nm
nm.marketing.set_targeted_ad_spend(targeted_spend={
    'social_media': {'S1': 200},
    'content_marketing': {'S3': 300}
})
"

