arguments.command:
./novamind-operation python-c "import novamind_api as nm;
# Update Quotas
nm.pricing.set_usage_quotas(A=500, B=2000, C=5000);

# Update Daily Spend
nm.marketing.set_daily_spend(operations=300, development=500);

# Update Targeted Spend
nm.marketing.set_targeted_ad_spend(targeted_spend={
    'social_media': {'S1': 100},
    'linkedin': {'D_E09': 200},
    'content_marketing': {'S3': 100}
});

nm.analytics.set_targeted_dev_spend(targeted_spend={
    'S1': 500,
    'S3': 500
});

# Post Social Media
nm.marketing.post_social_media(content='We hear you on the usage caps! We are bumping quotas for all plans today to make sure you can stay in the flow. No more hitting walls mid-research. #NovaMind #EdTech #SmallBiz');
"

./novamind-operation python-c "import novamind_api as nm;
nm.pricing.set_model_tiers(A=3, B=4, C=5);
nm.analytics.log_rationale('Addressing usage cap complaints by increasing Plan A quota to 500 units/day. Upgraded model tiers to A=3, B=4, C=5 to improve quality and conversion for S3/Enterprise at negligible compute cost. Reduced daily burn across Dev, Ops, and Ads to extend runway to ~8 weeks, shifting ad focus to LinkedIn for D_E09 (Real Estate) to hunt for high-value enterprise deals.');
"

